// Retell sends events at different paths depending on event type
// Check all possible locations for the event field
const body = $input.first().json.body || $input.first().json;
const event = body.event || $input.first().json.event || '';

// Also require a transcript to exist (blocks call_started which has empty transcript)
const call = body.call || body;
const transcript = call.transcript || '';

if (event !== 'call_analyzed') {
  // Not a call_analyzed event - stop processing
  return [];
}

if (!transcript || transcript.trim() === '') {
  // call_analyzed but no transcript yet - stop processing  
  return [];
}

// Valid call_analyzed with transcript - pass through
return $input.first().json;

const body = $input.first().json.body || $input.first().json;
const call = body.call || body;

return {
  call_id: call.call_id || '',
  agent_id: call.agent_id || '',
  from_number: call.from_number || '',
  to_number: call.to_number || '',
  transcript: call.transcript || '',
  duration_seconds: Math.round((call.end_timestamp - call.start_timestamp) / 1000) || 0,
  disconnection_reason: call.disconnection_reason || '',
  call_analysis: call.call_analysis || {},
  call_timestamp: new Date().toISOString()
};

const clients = $input.first().json;
const callData = $('Extract Call Data').first().json;
const client = Array.isArray(clients) ? clients[0] : clients;

if (!client || !client.company_name) {
  return {
    ...callData,
    client_found: false,
    company_name: 'Unknown', agent_name: 'Unknown',
    lead_phone: '', lead_email: '',
    notification_email_2: '', notification_email_3: '',
    notification_sms_2: '', notification_sms_3: '',
    twilio_from: '', timezone: 'America/Chicago'
  };
}

return {
  ...callData,
  client_found: true,
  company_name: client.company_name || '',
  agent_name: client.agent_name || '',
  lead_phone: client.lead_phone || '',
  lead_email: client.lead_email || '',
  notification_email_2: client.notification_email_2 || '',
  notification_email_3: client.notification_email_3 || '',
  notification_sms_2: client.notification_sms_2 || '',
  notification_sms_3: client.notification_sms_3 || '',
  twilio_from: client.twilio_from || client.twilio_number || '',
  timezone: client.timezone || 'America/Chicago',
  lead_contact_method: client.lead_contact_method || 'Both'
};

